SELECT product_id, calculated_profit, profit_percentage
FROM profit_analysis
WHERE period_start <= '2023-07-31' AND period_end >= '2023-07-01';

SELECT MAX(production_cost) AS peak_production_cost
FROM production_schedule
WHERE scheduled_date >= '2023-08-01';

SELECT product_id, MAX(calculated_profit) AS highest_profit
FROM profit_analysis
GROUP BY product_id;
